  const filteredTableRows = useMemo(() => {
    let rows = [...tableRows];
    if (tableSearch.length >= 2) {
      const q = tableSearch.toLowerCase();
      rows = rows.filter(r => Object.values(r.data||{}).some(v => String(v||"").toLowerCase().includes(q)));
    }
    for (const f of tableFilters) {
      rows = rows.filter(r => {
        const val = (r.data||{})[f.columnId];
        switch(f.operator) {
          case 'contains': return String(val||"").toLowerCase().includes(String(f.value).toLowerCase());
          case 'equals': return String(val) === String(f.value);
          case 'not_equals': return String(val) !== String(f.value);
          case 'gt': return Number(val) > Number(f.value);
          case 'lt': return Number(val) < Number(f.value);
          case 'isEmpty': return !val && val !== 0;
          case 'isNotEmpty': return !!val || val === 0;
          default: return true;
        }
      });
    }
    if (tableSort.col) {
      const col = tableColumns.find(c => c.id === tableSort.col);
      rows.sort((a, b) => {
        let va = (a.data||{})[tableSort.col]||"", vb = (b.data||{})[tableSort.col]||"";
        if (col?.type === 'number' || col?.type === 'rating') { va = Number(va)||0; vb = Number(vb)||0; return tableSort.dir==='asc'? va-vb : vb-va; }
        return tableSort.dir==='asc'? String(va).localeCompare(String(vb)) : String(vb).localeCompare(String(va));
      });
    }
    return rows;
  }, [tableRows, tableSearch, tableFilters, tableSort, tableColumns]);
  const paginatedTableRows = useMemo(() => filteredTableRows.slice(tablePage*TABLE_PAGE_SIZE, (tablePage+1)*TABLE_PAGE_SIZE), [filteredTableRows, tablePage]);
  const tableTotalPages = Math.ceil(filteredTableRows.length / TABLE_PAGE_SIZE);
